    "python_code": "def generate_inputs(device):\n    import torch\n    total_elements = 128 * 4096\n    block_size = 256\n    last_block_start = total_elements - 256\n    predictions = torch.zeros(128, 4096, dtype=torch.float32, device=device)\n    targets = torch.zeros(128, 4096, dtype=torch.float32, device=device)\n    # Set last 256 elements to produce large diff\n    predictions.view(-1)[last_block_start:] = 10.0\n    targets.view(-1)[last_block_start:] = 0.0\n    return [predictions, targets]"
